 1	import type { FC } from 'react';
 2	import { useWatch } from 'react-hook-form';
 3	
 4	import ExpandableReviewSection from '@components/ExpandableReviewSection/ExpandableReviewSection';
 5	import {
 6	  DescriptionList,
 7	  DescriptionListDescription,
 8	  DescriptionListGroup,
 9	  DescriptionListTerm,
10	  useWizardContext,
11	} from '@patternfly/react-core';
12	import { useForkliftTranslation } from '@utils/i18n';
13	
14	import { planStepNames, PlanWizardStepId } from '../../constants';
15	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
16	import { hasLiveMigrationProviderType } from '../../utils/hasLiveMigrationProviderType';
17	import { hasWarmMigrationProviderType } from '../../utils/hasWarmMigrationProviderType';
18	import { GeneralFormFieldId } from '../general-information/constants';
19	import { MigrationTypeFieldId, migrationTypeLabels } from '../migration-type/constants';
20	
21	const MigrationTypeReviewSection: FC<{ isLiveMigrationFeatureEnabled: boolean }> = ({
22	  isLiveMigrationFeatureEnabled,
23	}) => {
24	  const { t } = useForkliftTranslation();
25	  const { goToStepById } = useWizardContext();
26	  const { control } = useCreatePlanFormContext();
27	  const [migrationType, sourceProvider] = useWatch({
28	    control,
29	    name: [MigrationTypeFieldId.MigrationType, GeneralFormFieldId.SourceProvider],
30	  });
31	
32	  const planSupportMigrationTypes =
33	    hasWarmMigrationProviderType(sourceProvider) ||
34	    (hasLiveMigrationProviderType(sourceProvider) && isLiveMigrationFeatureEnabled);
35	
36	  if (!planSupportMigrationTypes) return null;
37	
38	  return (
39	    <ExpandableReviewSection
40	      title={planStepNames[PlanWizardStepId.MigrationType]}
41	      testId="review-migration-type-section"
42	      onEditClick={() => {
43	        goToStepById(PlanWizardStepId.MigrationType);
44	      }}
45	    >
46	      <DescriptionList isHorizontal horizontalTermWidthModifier={{ default: '18ch' }}>
47	        <DescriptionListGroup>
48	          <DescriptionListTerm>{t('Migration type')}</DescriptionListTerm>
49	          <DescriptionListDescription data-testid="review-migration-type">
50	            {migrationTypeLabels[migrationType]}
51	          </DescriptionListDescription>
52	        </DescriptionListGroup>
53	      </DescriptionList>
54	    </ExpandableReviewSection>
55	  );
56	};
57	
58	export default MigrationTypeReviewSection;

